// Normalize Calendly webhook payload
const event = $json.payload || $json;
const invitee = event.invitee || {};
const tracking = invitee.tracking || {};
const questions = invitee.questions_and_answers || [];

// Extract custom answers from Calendly form
const getAnswer = (q) => questions.find(qa => qa.question?.toLowerCase().includes(q.toLowerCase()))?.answer || '';

return [{
  json: {
    event_type: event.event_type?.name || 'Discovery Call',
    meeting_time: event.start_time || event.scheduled_event?.start_time || '',
    meeting_time_formatted: new Date(event.start_time || '').toLocaleString('en-GB', { timeZone: 'Asia/Dubai', weekday: 'short', day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' }),
    prospect_name: invitee.name || '',
    prospect_first_name: (invitee.name || '').split(' ')[0],
    prospect_email: invitee.email || '',
    calendly_uuid: event.uuid || '',
    company_name: getAnswer('company') || tracking.utm_content || '',
    role: getAnswer('role') || getAnswer('title') || '',
    biggest_challenge: getAnswer('challenge') || getAnswer('problem') || '',
    utm_source: tracking.utm_source || '',
    utm_medium: tracking.utm_medium || '',
    utm_campaign: tracking.utm_campaign || '',
    sequence_id: tracking.utm_campaign || 'unknown',
    booked_at: new Date().toISOString()
  }
}];

// Merge Calendly + Proxycurl + KommoCRM context
const calendly = $('Normalize Calendly Payload').all()[0].json;
const company = $('Proxycurl — Enrich Company').all()[0].json || {};
const crm = $('KommoCRM — Pull Deal Context').all()[0].json || {};

return [{
  json: {
    ...calendly,
    company_description: company.description || '',
    employee_count: company.company_size || crm.employee_count || '',
    industry: company.industry || crm.industry || '',
    tech_stack: crm.tech_stack || '',
    fb_ads_running: crm.fb_ads_running || false,
    avg_engagement_rate: crm.avg_engagement_rate || '',
    icp_segment: crm.icp_segment || '',
    icp_score: crm.icp_score || '',
    region: crm.region || 'MENA',
    signal_type: crm.signal_type || '',
    signal_date: crm.signal_date || '',
    decision_maker_linkedin: crm.decision_maker_linkedin || '',
    kommo_deal_id: crm.deal_id || ''
  }
}];

