// Select proposal tier and currency based on CRM data
const crm = $json;
const region = crm.region || 'MENA';
const score = crm.icp_score || 60;
const segment = crm.icp_segment || 'secondary';

const currency = region === 'EU' ? 'GBP' : region === 'US' ? 'USD' : 'AED';
const currencySymbol = region === 'EU' ? '£' : region === 'US' ? '$' : 'AED';

// Tier recommendation based on ICP score
const tier = score >= 85 ? 'Full Partner' : score >= 70 ? 'Growth Retainer' : 'Brand Sprint';

// Pricing in local currency
const pricing = {
  AED: { brand_sprint: 'AED 18,500', growth_retainer: 'AED 12,000/mo', full_partner: 'AED 22,000/mo' },
  GBP: { brand_sprint: '£4,000', growth_retainer: '£2,500/mo', full_partner: '£4,500/mo' },
  USD: { brand_sprint: '$5,000', growth_retainer: '$3,000/mo', full_partner: '$5,500/mo' }
};

const prices = pricing[currency];

// Match case study to vertical
const industry = (crm.industry || '').toLowerCase();
const caseStudy = industry.includes('tech') || industry.includes('software') || industry.includes('saas') 
  ? { name: 'Devolon', result: '3x qualified pipeline in 60 days', industry: 'B2B Tech' }
  : industry.includes('retail') || industry.includes('furniture') || industry.includes('home')
  ? { name: 'Holz Concepts', result: '40% increase in average order value', industry: 'Premium Retail' }
  : { name: 'Flow Meditation', result: '2.8x ROAS on Meta within 45 days', industry: 'Wellness / D2C' };

return [{
  json: {
    ...crm,
    currency,
    currency_symbol: currencySymbol,
    recommended_tier: tier,
    tier_1_price: prices.brand_sprint,
    tier_2_price: prices.growth_retainer,
    tier_3_price: prices.full_partner,
    case_study_name: caseStudy.name,
    case_study_result: caseStudy.result,
    case_study_industry: caseStudy.industry,
    proposal_date: new Date().toLocaleDateString('en-GB'),
    expiry_date: new Date(Date.now() + 7 * 86400000).toLocaleDateString('en-GB')
  }
}];

